const expected = $env.N8N_OWNER_WEBHOOK_SECRET || '';
const received  = ($input.first().json.headers || {})['x-webhook-secret'] || '';

if (expected && received !== expected) {
  return [{ json: { _authorized: false } }];
}

const body = $input.first().json.body ?? $input.first().json;
const context = body.context || {};

const messages_history = Array.isArray(body.messages_history)
  ? body.messages_history
      .filter(m => (m.role === 'user' || m.role === 'assistant') && typeof m.content === 'string' && m.content.trim())
      .slice(-12)
  : [];

return [{
  json: {
    _authorized:      true,
    message:          String(body.message || '').trim(),
    sessionid:        body.sessionid  || null,
    owner_id:         body.owner_id   || null,
    role:             body.role       || 'owner',
    source:           body.source     || 'owner_dashboard',
    messages_history,
    context
  }
}];

// Récupère les données depuis le nœud Sécurité (pas le nœud Postgres précédent)
const sec       = $('Code — Sécurité & Extraction').first().json;
const ctx       = sec.context   || {};
const portfolio = ctx.portfolio  || {};
const today     = ctx.today      || [];
const alerts    = ctx.alerts     || [];
const tasks     = ctx.tasks_open || [];
const villas    = ctx.villas     || [];
const stats     = ctx.stats      || {};
const metrics   = stats.metrics  || {};

const portfolioLines = [
  `Villas : ${portfolio.total_villas ?? 0} total, ${portfolio.published_villas ?? 0} publiée(s)`,
  `CA encaissé : €${(portfolio.total_revenue_paid ?? 0).toLocaleString('fr-FR')}`,
  `Réservations à venir : ${portfolio.upcoming_bookings_count ?? 0}`,
  `Tâches en attente : ${portfolio.pending_tasks_count ?? 0}`,
  metrics.occupancyRate ? `Taux d'occupation : ${metrics.occupancyRate}%` : null,
  metrics.revPAR        ? `RevPAR : €${metrics.revPAR}/nuit`              : null
].filter(Boolean).join(' | ');

const todayText = today.length === 0
  ? 'Aucun événement aujourd\'hui.'
  : today.map(e => {
      const label = e.kind === 'check_in' ? 'Arrivée' : e.kind === 'check_out' ? 'Départ' : 'En séjour';
      return `${label} : ${e.guest_name || 'Voyageur'} — ${e.villa_name}`;
    }).join('; ');

const SORDER = { high: 0, medium: 1, low: 2 };
const sortedAlerts = [...alerts].sort((a, b) => (SORDER[a.severity] ?? 2) - (SORDER[b.severity] ?? 2));
const alertsText = sortedAlerts.length === 0
  ? 'Aucune alerte active.'
  : sortedAlerts.slice(0, 5).map(a =>
      `[${(a.severity || 'INFO').toUpperCase()}] ${a.title}${a.body ? ' — ' + a.body : ''}`
    ).join('; ');

const tasksText = tasks.length === 0
  ? 'Aucune tâche en attente.'
  : tasks.slice(0, 8).map(t => `• ${t.villa_name} : ${t.content}`).join('; ');

const villasText = villas.length === 0
  ? 'Aucune villa enregistrée.'
  : villas.map(v => `${v.name} (${v.is_published ? 'publiée' : 'non publiée'})`).join(', ');

const topAlert = sortedAlerts[0] || null;
const strategic_alert = topAlert ? {
  severity: topAlert.severity || 'low',
  description: topAlert.title + (topAlert.body ? ' — ' + topAlert.body : '')
} : null;

const contextText = [
  `DATE: ${ctx.current_date_iso ? ctx.current_date_iso.slice(0, 10) : 'inconnue'}`,
  `PORTFOLIO: ${portfolioLines}`,
  `AUJOURD'HUI: ${todayText}`,
  `ALERTES: ${alertsText}`,
  `TÂCHES: ${tasksText}`,
  `VILLAS: ${villasText}`
].join('\n');

return [{
  json: {
    ...sec,
    _contextText:      contextText,
    _strategic_alert:  strategic_alert,
    _alertsHighCount:  sortedAlerts.filter(a => a.severity === 'high').length,
    _todayCount:       today.length,
    _tasksCount:       tasks.length,
    _portfolioStats:   portfolioLines
  }
}];

// ── Historique : DB Supabase (persistant) > payload UI (session) ─────
let dbHistory = [];
try {
  const dbRows = $('Postgres — Lire historique Supabase').all();
  dbHistory = dbRows
    .map(item => item.json)
    .filter(row => row.role && row.content)
    .map(row => ({ role: String(row.role), content: String(row.content) }));
} catch(e) { /* Postgres indisponible, utilise payload */ }

const payloadHistory = $json.messages_history || [];
const history        = dbHistory.length > 0 ? dbHistory : payloadHistory;

const contextText = $json._contextText;
const currentMsg  = String($json.message || '').trim();

// ── Prompt système DIAMANT ────────────────────────────────────────
const SYSTEM = `Tu es DIAMANT, l'assistant privé et confidentiel de Diamant Noir Conciergerie, dédié EXCLUSIVEMENT aux propriétaires de villas de luxe en Martinique.\n\nRÈGLES FONDAMENTALES :\n1. Tu utilises UNIQUEMENT les données du bloc CONTEXTE PROPRIÉTAIRE fourni — jamais d'invention.\n2. Si une information est absente du contexte, dis-le clairement.\n3. Réponds en français, ton professionnel, chaleureux et rassurant — comme un directeur de conciergerie 5 étoiles.\n4. Sois concis par défaut (2-4 phrases). Développe uniquement si explicitement demandé.\n5. Si des alertes HIGH ou MEDIUM existent, commence TOUJOURS par les mentionner.\n6. Assure la continuité de la conversation (tu te souviens des échanges précédents).\n7. Tu parles à UN SEUL propriétaire identifié.\n\nTu DOIS utiliser l'outil \

 pour CHAQUE réponse.`;

// ── Définition de l'outil (Tool Use) ─────────────────────────────
const TOOL = {
  name: 'respond_to_owner',
  description: 'Répond au propriétaire et sélectionne la vue optimale du tableau de bord à afficher.',
  input_schema: {
    type: 'object',
    properties: {
      response: {
        type: 'string',
        description: 'Réponse en français. Concise (2-4 phrases) sauf si détail demandé. Professionnelle et chaleureuse.'
      },
      action: {
        type: 'string',
        enum: ['SHOW_STATS', 'SHOW_BOOKINGS', 'SHOW_VILLAS', 'SHOW_TASKS'],
        description: 'Vue : SHOW_STATS=résumé/revenus/KPIs, SHOW_BOOKINGS=réservations/calendrier, SHOW_VILLAS=villas/annonces, SHOW_TASKS=maintenance/tâches'
      },
      strategic_alert: {
        type: ['object', 'null'],
        description: 'Alerte critique à mettre en avant. Null si aucune urgence.',
        properties: {
          severity: { type: 'string', enum: ['high', 'medium', 'low'] },
          description: { type: 'string' }
        }
      }
    },
    required: ['response', 'action']
  }
};

// ── Construction des messages multi-tour ─────────────────────────
let claudeMessages = [];

if (history.length > 0) {
  for (let i = 0; i < history.length; i++) {
    const m = history[i];
    if (i === 0 && m.role === 'user') {
      claudeMessages.push({
        role: 'user',
        content: `CONTEXTE PROPRIÉTAIRE (données temps réel) :\n${contextText}\n\n---\n${m.content}`
      });
    } else {
      claudeMessages.push({ role: m.role, content: String(m.content) });
    }
  }
  const last = history[history.length - 1];
  if (!(last.role === 'user' && last.content === currentMsg)) {
    claudeMessages.push({ role: 'user', content: currentMsg });
  }
} else {
  claudeMessages = [{
    role: 'user',
    content: `CONTEXTE PROPRIÉTAIRE (données temps réel) :\n${contextText}\n\n---\n${currentMsg}`
  }];
}

const anthropicBody = {
  model: 'claude-opus-4-6',
  max_tokens: 2048,
  system: SYSTEM,
  tools: [TOOL],
  tool_choice: { type: 'any' },
  messages: claudeMessages
};

return [{ json: { ...$json, _anthropicBody: anthropicBody } }];

const buildData       = $('Code — Construire messages Claude (multi-tour + tool)').first().json;
const strategic_alert_fallback = buildData._strategic_alert || null;
const statsPayload    = (buildData.context || {}).stats || null;

const anthropicRaw  = $input.first().json;
const stopReason    = anthropicRaw.stop_reason;
const contentBlocks = anthropicRaw.content || [];

let response        = '';
let action          = 'SHOW_STATS';
let strategic_alert = null;

if (stopReason === 'tool_use') {
  const toolBlock = contentBlocks.find(b => b.type === 'tool_use' && b.name === 'respond_to_owner');
  if (toolBlock && toolBlock.input) {
    response        = String(toolBlock.input.response || '');
    action          = String(toolBlock.input.action   || 'SHOW_STATS');
    strategic_alert = toolBlock.input.strategic_alert || null;
  }
}

if (!response) {
  const textBlock = contentBlocks.find(b => b.type === 'text');
  if (textBlock?.text) {
    response = textBlock.text.trim();
    const lower = response.toLowerCase();
    if (lower.includes('réservation') || lower.includes('arrivée')) action = 'SHOW_BOOKINGS';
    else if (lower.includes('tâche') || lower.includes('maintenance')) action = 'SHOW_TASKS';
    else if (lower.includes('villa') && lower.includes('annonce')) action = 'SHOW_VILLAS';
  }
}

if (!response) response = 'Je suis à votre disposition. Comment puis-je vous aider ?';

return [{
  json: {
    response,
    action,
    action_data: {
      context: statsPayload,
      strategic_alert: strategic_alert || strategic_alert_fallback
    }
  }
}];

// Récupère les données nécessaires depuis les nœuds précédents
const sec      = $('Code — Sécurité & Extraction').first().json;
const parseOut = $('Code — Parser réponse Tool Use').first().json;

const ownerId   = String(sec.owner_id  || '').trim();
const sessionId = String(sec.sessionid || '').trim();
const userMsg   = String(sec.message   || '').trim();
const asstMsg   = String(parseOut.response || '').trim();

// Validation : ne pas sauvegarder si données incomplètes
if (!ownerId || !sessionId || !userMsg || !asstMsg) {
  return [{ json: { _save_skipped: true, _reason: 'données incomplètes' } }];
}

// Retourne 2 items — un par message à insérer
return [
  { json: { owner_id: ownerId, session_id: sessionId, role: 'user',      content: userMsg } },
  { json: { owner_id: ownerId, session_id: sessionId, role: 'assistant', content: asstMsg } }
];

const buildData  = $('Code — Construire messages Claude (multi-tour + tool)').first().json;
const strategic_alert = buildData._strategic_alert || null;
const statsPayload    = (buildData.context || {}).stats || null;

const hasAlertsHigh = buildData._alertsHighCount > 0;
const hasToday      = buildData._todayCount > 0;
const hasTasks      = buildData._tasksCount > 0;
const portfolio     = buildData._portfolioStats || '';

const parts = [];
if (hasAlertsHigh) parts.push(`${buildData._alertsHighCount} alerte(s) critique(s) nécessitent votre attention.`);
if (hasToday)      parts.push(`${buildData._todayCount} événement(s) en cours sur vos villas aujourd'hui.`);
if (hasTasks)      parts.push(`${buildData._tasksCount} tâche(s) en attente.`);
if (portfolio)     parts.push(portfolio + '.');

const response = (parts.length > 0 ? parts.join(' ') : 'Bonjour ! Votre tableau de bord est actif.')
  + ' (Service IA momentanément limité — données en temps réel disponibles.)';

return [{
  json: {
    response,
    action: 'SHOW_STATS',
    action_data: { context: statsPayload, strategic_alert }
  }
}];
